      options: [{ id: `A`, text: `<table style="border-collapse:collapse;margin:8px auto;font-size:0.95em"><thead><tr><th style="border:1px solid var(--border);padding:4px 9px;text-align:left">x</th><th style="border:1px solid var(--border);padding:4px 9px;text-align:left">y</th></tr></thead><tbody><tr><td style="border:1px solid var(--border);padding:4px 9px">&minus;1</td><td style="border:1px solid var(--border);padding:4px 9px">1</td></tr><tr><td style="border:1px solid var(--border);padding:4px 9px">0</td><td style="border:1px solid var(--border);padding:4px 9px">0</td></tr><tr><td style="border:1px solid var(--border);padding:4px 9px">1</td><td style="border:1px solid var(--border);padding:4px 9px">5</td></tr></tbody></table>` }, { id: `B`, text: `<table style="border-collapse:collapse;margin:8px auto;font-size:0.95em"><thead><tr><th style="border:1px solid var(--border);padding:4px 9px;text-align:left">x</th><th style="border:1px solid var(--border);padding:4px 9px;text-align:left">y</th></tr></thead><tbody><tr><td style="border:1px solid var(--border);padding:4px 9px">&minus;1</td><td style="border:1px solid var(--border);padding:4px 9px">1</td></tr><tr><td style="border:1px solid var(--border);padding:4px 9px">0</td><td style="border:1px solid var(--border);padding:4px 9px">3</td></tr><tr><td style="border:1px solid var(--border);padding:4px 9px">1</td><td style="border:1px solid var(--border);padding:4px 9px">5</td></tr></tbody></table>` }, { id: `C`, text: `<table style="border-collapse:collapse;margin:8px auto;font-size:0.95em"><thead><tr><th style="border:1px solid var(--border);padding:4px 9px;text-align:left">x</th><th style="border:1px solid var(--border);padding:4px 9px;text-align:left">y</th></tr></thead><tbody><tr><td style="border:1px solid var(--border);padding:4px 9px">&minus;1</td><td style="border:1px solid var(--border);padding:4px 9px">&minus;1</td></tr><tr><td style="border:1px solid var(--border);padding:4px 9px">0</td><td style="border:1px solid var(--border);padding:4px 9px">2</td></tr><tr><td style="border:1px solid var(--border);padding:4px 9px">1</td><td style="border:1px solid var(--border);padding:4px 9px">5</td></tr></tbody></table>` }, { id: `D`, text: `<table style="border-collapse:collapse;margin:8px auto;font-size:0.95em"><thead><tr><th style="border:1px solid var(--border);padding:4px 9px;text-align:left">x</th><th style="border:1px solid var(--border);padding:4px 9px;text-align:left">y</th></tr></thead><tbody><tr><td style="border:1px solid var(--border);padding:4px 9px">&minus;1</td><td style="border:1px solid var(--border);padding:4px 9px">5</td></tr><tr><td style="border:1px solid var(--border);padding:4px 9px">0</td><td style="border:1px solid var(--border);padding:4px 9px">2</td></tr><tr><td style="border:1px solid var(--border);padding:4px 9px">1</td><td style="border:1px solid var(--border);padding:4px 9px">&minus;1</td></tr></tbody></table>` }],
